vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = texture(sampler_main, vUv).xyz;
    vec2 texc = 0.37 + 0.55*ret.xy;
vec4 noise2 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*0.33
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(12.2,0.1,2.1)*0.01   //MilkDrop2077 color mod
                     *vec3(.2,0.7,.8)*0.9 //MilkDrop2077 color mod
                     );

if(ret.x+ret.y+ret.z>0.52)ret += (noise2)*0.72;
ret *= texture(sampler_clipboard03, texc) * ret.z * 3;

    // vec3 crisp = texture(sampler_main, vUv).xyz;
     //   vec3 blurry = GetBlur3(vUv);
        ret -= (GetBlur3(vUv)/8);

  fragColor = ret;
}
